"use strict";(globalThis.webpackChunkrock_docs=globalThis.webpackChunkrock_docs||[]).push([[8733],{85371(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"1.10.x","label":"1.10.x","banner":null,"badge":true,"noIndex":false,"className":"docs-version-1.10.x","isLast":false,"docsSidebars":{},"docs":{"Getting Started/installation":{"id":"Getting Started/installation","title":"Installation","description":"This document explains how to install and set up the ROCK development environment using both uv and pip. The project is a Reinforcement Open Construction Kit that supports various components."},"Getting Started/quickstart":{"id":"Getting Started/quickstart","title":"Getting Started","description":"This guide will demonstrate how to use ROCK to create and manage reinforcement learning environments through complete examples."},"Getting Started/rock-agent":{"id":"Getting Started/rock-agent","title":"Rock Agent Quick Start","description":"ROCK provides two parallel ways to use agents, each suited to a different scenario:"},"Getting Started/rockroll":{"id":"Getting Started/rockroll","title":"ROCK & ROLL Quick Start Guide","description":"This guide will walk you through running a reinforcement learning training example based on the Sokoban game, using ROLL (the training framework) and ROCK (the environment management tool)."},"overview":{"id":"overview","title":"Overview","description":"ROCK (Reinforcement Open Construction Kit) is an open-source reinforcement learning environment development framework designed to simplify the development, deployment, and management of reinforcement learning environments."},"References/api":{"id":"References/api","title":"API Reference","description":"This guide provides detailed information about the core API services provided by the ROCK platform, including sandbox environment management and GEM environment interaction."},"References/Python SDK References/codes":{"id":"References/Python SDK References/codes","title":"Error Codes","description":"Error code definitions and categories for error handling and retry strategies."},"References/Python SDK References/deploy":{"id":"References/Python SDK References/deploy","title":"Deploy","description":"Sandbox resource deployment manager for local directory deployment and template formatting."},"References/Python SDK References/file_system":{"id":"References/Python SDK References/file_system","title":"FileSystem","description":"File system interface for sandbox environment operations including permission and ownership management."},"References/Python SDK References/job":{"id":"References/Python SDK References/job","title":"Use Job to Run Agent","description":"This is the reference for Job, one of ROCK\'s two parallel ways to use agents. Its core API is rock.sdk.job.Job with JobConfig, used to run an agent evaluation/task in a sandbox. Two backends are supported: Bash Job and Harbor Bench Job."},"References/Python SDK References/model-service":{"id":"References/Python SDK References/model-service","title":"Model Service (Experimental)","description":"The Model Service provided by ROCK is responsible for handling AI model call communications, serving as a communication bridge between agents and training frameworks (such as Roll) or actual LLM inference services."},"References/Python SDK References/python_sdk":{"id":"References/Python SDK References/python_sdk","title":"Python SDK Reference","description":"This guide provides detailed information on how to use the ROCK SDK for development, including sandbox environment management and GEM environment interaction."},"References/Python SDK References/remote_user":{"id":"References/Python SDK References/remote_user","title":"Remote User","description":"Remote user management for creating and managing users in the sandbox."},"References/Python SDK References/rock-agent":{"id":"References/Python SDK References/rock-agent","title":"Install Agent in Sandbox (Experimental)","description":"This is the reference for install-agent, one of ROCK\'s two parallel ways to use agents. Its core API is sandbox.agent.install() and sandbox.agent.run(prompt), used to install and run an agent inside a single sandbox."},"References/Python SDK References/runtime-env":{"id":"References/Python SDK References/runtime-env","title":"RuntimeEnv","description":"The RuntimeEnv module is used to manage language runtime environments in the sandbox (currently providing Python / Node.js)."},"References/Python SDK References/sandbox":{"id":"References/Python SDK References/sandbox","title":"Handling Large Files and Long Command Outputs","description":"arun"},"References/Python SDK References/swe-bench-evaluation":{"id":"References/Python SDK References/swe-bench-evaluation","title":"SWE-Bench Evaluation","description":"This guide demonstrates how to use the ROCK SDK to run SWE-Bench Verified evaluations, including sandbox setup, Agent integration, test environment preparation, and result parsing."},"Release Notes/index":{"id":"Release Notes/index","title":"Release Notes","description":"* release v1.10.0"},"Release Notes/v1.10.0":{"id":"Release Notes/v1.10.0","title":"v1.10.0","description":"Release Date"},"User Guides/configuration":{"id":"User Guides/configuration","title":"Configuration","description":"This guide provides detailed instructions on how to configure the ROCK environment to meet different usage requirements, including local development, testing, and production deployment."},"User Guides/sandbox_create_benchmark":{"id":"User Guides/sandbox_create_benchmark","title":"ROCK Sandbox Large-Scale Concurrent Creation Benchmark Report","description":"1. Background"},"User Guides/sandbox_proxy":{"id":"User Guides/sandbox_proxy","title":"Sandbox Proxy","description":"ROCK Admin exposes a proxy layer that lets you reach services running inside a sandbox from outside the cluster, without giving each sandbox its own public address. The proxy supports two transport modes:"},"User Guides/scheduler":{"id":"User Guides/scheduler","title":"Scheduler","description":"The ROCK scheduler is a periodic task framework embedded in the admin service. It dispatches background maintenance tasks (image cleanup, file cleanup, container cleanup, image pre-pull, custom tasks, ...) to every alive Ray worker on a configurable interval, so worker nodes stay healthy without manual intervention."}}}}')}}]);